class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def count_set_bits_at_position(num, x):
            total = 0
            divider = 1 << x
            remainder = num % divider
            total += (num // divider) * (divider // 2)
            if remainder >= (divider // 2):
                total += remainder - (divider // 2) + 1
            return total

        def count_accumulated_price(num, x):
            total = 0
            for i in range(x, 65, x):
                total += count_set_bits_at_position(num, i)
            return total

        def binary_search(k, x):
            left, right = 0, 10**18
            while left < right:
                mid = (left + right + 1) // 2
                if count_accumulated_price(mid, x) <= k:
                    left = mid
                else:
                    right = mid - 1
            return left

        return binary_search(k, x)

